// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onLoad() {
	// the route order field needs to only allow selection of valid route orders.
	// this script is connected to the Tasker Def - onLoad - Set Route Choices to repopulate teh option list for the route order drop down
	// NOTE: since the options don't always exist, it appears that the display values are not present with all options above 1.
	// this could be fixed by adding 50 - 100 values just to make it look good. 
	// or, something might have to be changed in the list view to show the value instead of the display value 

	// STRY0074601
	if(g_form.getValue('tasking_authority.u_external_flag') == 'true'){
			g_form.showFieldMsg("tasking_authority", getMessage('Tasker - The OU selected is an external Organizational Unit'), "info");
	}

	if (g_form.getValue('parent') + '' != '') { 
		g_form.setReadOnly('primary_office',true);
		g_form.setReadOnly('tasking_authority',true);
	} else{
		// top task template 
		g_form.setReadOnly('tasking_authority',false);
		if(g_form.getValue('tasking_authority.u_external_flag') == 'true'){
			g_form.setReadOnly('primary_office',false);
		} else{
			// STRY0071489 - If new setting for system property definie if Primary Office Must Match Internal Tasking Authority
			if(g_scratchpad.primary_office_must_match_Internal_tasking_authority != 'true'){
				g_form.setReadOnly('primary_office',false);
			} else{
				g_form.setReadOnly('primary_office',true);
			}
		}
	}	

	g_form.clearOptions('route_order');
	var i = 0;
	while (i <= g_scratchpad.maxRoutes){
		i++;
		g_form.addOption('route_order', i, i);
	}
	// set the route order back after reloading the dropdown list
	g_form.setValue('route_order',g_scratchpad.currentRouteValue,g_scratchpad.currentRouteValue);

	// STRY0076612 - SEQ - STRETCH - Template Task Form – TASK ORDER Location and Information Message
	if(g_scratchpad.currentRouteValue > 1 ){
		var msg = getMessage('Tasker - Task is Dependent on lower-order Tasks');
		g_form.showFieldMsg("route_order", msg, "info", false);
	}

}
